var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MERCENARIES_NPC_SUPPLEMENT_B","text":{"KOREA":"자, 잠깐! 난 총 버렸어! 투항할게!","JPN":"ま、待て！　俺は銃を捨てた！　降参だ！","ENG":"W-wait! I put my gun down! I surrender!","TWN":"等…等一下！我棄械投降！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARIES_NPC_SUPPLEMENT_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"아, 그래?","JPN":"あ、そうか？","ENG":"Oh, really?","TWN":"是喔？"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"그럼 그렇게 해…!","JPN":"じゃあ、勝手に降参してろ……！","ENG":"Then do as you wish...!","TWN":"那就…！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MERCENARIES_NPC_SUPPLEMENT_B","text":{"KOREA":"우아아악!!!","JPN":"うわああっ！！！","ENG":"Aaaahhh!!!","TWN":"哇啊啊啊！！！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","text":{"KOREA":"뭐야. 벌써 전부 당했나?","JPN":"なんだ。もう全員やられたのか？","ENG":"What the heck! Is everybody down?","TWN":"搞什麼？全軍覆沒嗎？"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"야, 네가 우두머리냐?","JPN":"おい、あんたが頭か？","ENG":"Hey, are you the captain?","TWN":"喂！你是帶頭的嗎？"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","text":{"KOREA":"우왓…! 어느새?!","JPN":"うわっ……！　いつの間に！？","ENG":"Wah?! H-how...?!","TWN":"哇…！你什麼時候？！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","text":{"KOREA":"맞아! 좀 맞으라고오!!!","JPN":"当たれ！　当たれええ！！！","ENG":"Get hit! Hit!!!","TWN":"對！吃子彈吧你！！！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L19_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"크하하하하! 공격이 눈에 뻔히 보이잖아!","JPN":"アハハハハ！　攻撃が丸見えなんだよ！","ENG":"Bwa hah hah hah! Your attacks are so obvious!","TWN":"哈哈哈哈！你的攻擊套路也太好懂！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"고작 그딴 실력으로 나한테 결투를 건 거냐?","JPN":"そんな実力でアタシに決闘を申し込んだのか？","ENG":"You tried to duel with me with those lousy skills?","TWN":"就這點能耐還敢來找我決鬥？"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","text":{"KOREA":"이… 망할, 하필이면 이럴 때 탄약이 걸리다니…","JPN":"この……クソッ、よりによってこんな時に弾詰まりが……！","ENG":"Why... Darn it, why does my gun have to be jammed now...","TWN":"唔…可惡！偏偏這個時候卡彈…"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"결투에선 운도 실력이지. 안 그래?","JPN":"決闘では運も実力だ。そう思わないか？","ENG":"But luck is also an ability in battle, isn’t it?","TWN":"戰鬥中運氣也是很重要的，你說是不？"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","face":"UNIT_IDLE"},"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","text":{"KOREA":"제, 젠자앙…!","JPN":"く、クソォ……！","ENG":"D-Darn it...!","TWN":"該死…！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","face":"UNIT_IDLE"},"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","text":{"KOREA":"으아아악…!","JPN":"うわああ……！","ENG":"Aaaah!","TWN":"呃啊啊啊…！"},"stage":{"bg":"SKY","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","text":{"KOREA":"어푸웁…! 살려줘! 난 수영 못 해!","JPN":"うぷっ……！　助けてくれ！　俺は泳げないんだ！","ENG":"Poof...! Help! I can’t swim!","TWN":"噗噗…！救命啊！我不會游泳！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"STAFF_NPC_DRAMA_ROBOT","text":{"KOREA":"안녕하세요, 여러분? 물에 빠지기 좋은 날씨죠?","JPN":"こんにちは、みなさん。水の中に入るにはちょうどいい天気だと思いませんか？","ENG":"Hello, everyone? Isn’t it a lovely day for a swim?","TWN":"大家好，今天的天氣很適合玩水對吧？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_NPC_DRAMA_ROBOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"응? 뭐야? 내가 내려오는 사이에 용병들이 전부 당한 건가?","JPN":"うん？　なに？　私が降りて来る間に傭兵が全部やられたの？","ENG":"Huh? What is it? Did she get all the mercenaries while I was coming down?","TWN":"什麼東西？我走下來這段時間就全軍覆沒啦？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"훗, 차라리 잘 됐네.","JPN":"フッ、むしろよかったわ。","ENG":"Ha, maybe it’s better this way.","TWN":"呵，這樣也好！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"어차피 촬영은 엉망이 됐고, 패배자들에겐 의뢰비도 줄 필요가 없어졌으니.","JPN":"どうせ撮影はダメになったし、負け犬に依頼代をあげる必要もなくなったんだから。","ENG":"The shoot is already a mess, and I don’t even have to pay the losers.","TWN":"現在拍攝也中斷了，而且他們任務失敗，我也沒必要付錢。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"컷!","JPN":"カット！","ENG":"Cut!","TWN":"Cut！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SNAP"},{"id":"L42_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"…이건… 정말 어처구니없군!","JPN":"……これは……もうメチャクチャだ！","ENG":"...This is... ridiculous!","TWN":"…這…我完全說不出話來！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"이건 감히 예고편이라 부르기 힘든 수준이야!","JPN":"もはや予告編だと呼べないくらいにな！","ENG":"This can’t even be called a trailer anymore!","TWN":"這根本不是預告片的水準吧！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"고작 이 한 번의 테이크로 내가 지금까지 쓴 각본은 쓰레기나 다름없어졌다고!","JPN":"たった一度のテイクで、私が今まで書いた脚本は台なしになってしまった！","ENG":"With this one take, all my scripts have turned into rubbish!","TWN":"光是這一場戲，就把我原本寫的劇本都變成垃圾啦！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"저거 봐. 감독도 잔뜩 흥분해있잖아?","JPN":"ほら。監督もすごい興奮してるし。","ENG":"Look at him. The director also lost his cool.","TWN":"看吧，導演也很生氣！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"저 정도면 굳이 옆에서 바람 잡을 필요도 없겠는데?","JPN":"あれじゃあ、隣で煽る必要もなさそうね。","ENG":"Him being like that, I guess there’s no need for a decoy.","TWN":"看導演氣成那樣，應該不需要我在旁邊煽風點火吧？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"눈빛 하나로 거대한 짐승들을 압도하는 카리스마!","JPN":"視線だけで巨大な獣たちを圧倒するカリスマ！","ENG":"Charismatic enough to dampen the animals’ spirits just with one’s eye gaze!","TWN":"一個眼神就震攝住大型動物的氣勢！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"무장괴한들을 압도하는 것도 모자라, 난투 그 자체를 즐기는 전투광의 모습!","JPN":"さらに武装集団を圧倒するだけでなく、乱闘自体を楽しむ戦闘狂の姿！","ENG":"Not only overpowering the gunmen, but also enjoying the fight itself, being a true combat maniac!","TWN":"不只是打趴那些武裝分子，而且還非常享受在大亂鬥裡面！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"유마 양! 당신의 모든 행동은 파벨라 그 자체야!","JPN":"ユマさん！　君はファヴェーラそのものだよ！","ENG":"Miss Yuma! You, yourself, are Fabella!","TWN":"游馬小姐！你的一言一行完全就是帕貝拉！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"…뭐?","JPN":"……はぁ？","ENG":"...What?","TWN":"…蛤？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"오늘 돌아가는 대로 내 쓰레기 같은 각본을 다시 써야겠군. 새로운 파벨라에게 걸맞은 내용으로 말이야.","JPN":"今日帰ったら私のダメな脚本を書き直さなければ。新しいファヴェーラに相応しい内容にな。","ENG":"I’ll have to rewrite my scripts all from the beginning. So that it fits the new Fabella.","TWN":"我今天回去就重寫我那垃圾劇本！我要為帕貝拉量身打造新劇本！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"감독님. 그렇다면 그 말씀의 뜻은…?","JPN":"監督。ということは、つまり……？","ENG":"Mr. Director. Then does that mean...?","TWN":"導演，您這話的意思是…？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"유마 양이 유혹의 함교 파벨라 역할을 맡아줬으면 하네!","JPN":"ユマさんが誘惑の艦橋でファヴェーラ役を演じてほしい！","ENG":"I want Miss Yuma to take the role of Fabella in The Bridge of Seduction!","TWN":"游馬小姐，希望你能演出誘惑的艦橋裡帕貝拉的角色！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"큭큭, 좋아. 이걸로 결투는 내 승리네.","JPN":"ククッ、そうか。これで決闘はアタシの勝ちだな。","ENG":"Hah hah, good. So I take the win.","TWN":"呵呵，好哇！那這場戰鬥是算我贏囉？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"그럼 돈도 주는 거겠지?","JPN":"じゃあ、金もくれるんだろう？","ENG":"That means I get paid, right?","TWN":"你會給我錢吧？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"그야 물론이지! 원하는 액수를 말하라고!","JPN":"そりゃもちろん！　望みの金額を提示してくれ！","ENG":"Of course! Just say the amount you wish to get paid!","TWN":"那當然！你說個數字吧！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"응? 거기까진 생각해본 적 없는데?","JPN":"うん？　そこまでは考えてなかった。","ENG":"Huh? I’ve never thought of that.","TWN":"數字喔？我還沒想過欸？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"주인님이랑 상의 좀 해봐도 되지?","JPN":"主様と相談してみてもいいか？","ENG":"Can I talk with my Mistress about that?","TWN":"我可以跟主人討論一下嗎？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"아니야!","JPN":"違う！","ENG":"No!","TWN":"不可以！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"엉?","JPN":"あ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"날 두고 다른 사람을 뽑았다고? 지금 제 정신으로 하는 소리야?","JPN":"私を置いて他の人を選んだの？　正気なの？","ENG":"You’re choosing a different person besides me? Are you out of your mind?","TWN":"竟然不選我選別人？你腦子沒燒壞吧？"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L19_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"이 여잔 그냥 자기 성격대로 구는 것뿐이잖아! 애초에 연기 같은 건 하지 않았어!","JPN":"この女はただ自分の性格のまま行動してるだけじゃない！　そもそも演技なんてやってもこなかったのよ！","ENG":"This girl’s was just being herself! She was never acting!","TWN":"這個女的根本就只是在演她自己！哪有什麼演技可言！"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"내가 여기까지 오려고 얼마나 많이 노력했는데! 주역까지 고작 한 걸음 남았었다고!","JPN":"ここまで来るために私がどんなに努力をしてきたと思ってるの？　主役まであと一歩だったのに！","ENG":"I tried so hard to get all the way here! I had just one step left to becoming the lead!","TWN":"我那麼努力才有今天！就差那麼一步就可以成為女主角！"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L24_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"그런데 이제 와서 본 적도 없는 깡패 하나가 내 자릴 꿰찬다고? 드라마가 장난이야?","JPN":"なのに、今さら見たこともないチンピラが私の役を奪う？　ドラマは子どもの遊びじゃないのよ！","ENG":"And now a gangster pops out of nowhere and takes my place? Is this a joke or what?","TWN":"現在一個來路不明的女流氓要搶走我的角色？拍戲是在開玩笑嗎？"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L25_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"너, 어디서 뭘 하다 온 거냐?","JPN":"あんた、どこで何をしてたんだ？","ENG":"Hey you, where were you?","TWN":"你，剛剛人在哪裡？"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"뭐…? 뭐가?","JPN":"はぁ……？　何が？","ENG":"Huh? W-what?","TWN":"什…？什麼意思？"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"아까 내가 날려버린 녀석들이랑 비슷한 냄새가 나는데?","JPN":"さっきアタシが飛ばしたやつらと似たようなニオイがする。","ENG":"You smell similar to the guys I dealt with earlier.","TWN":"你身上的味道和剛剛我打趴的那群人很像欸？"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"냄새? 네가 무슨 개라도 돼?","JPN":"ニオイ？　あなた、犬か何かなの？","ENG":"Smell? Are you a dog or something?","TWN":"味道？你是狗嗎？"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"하! 그래! 내 자릴 빼앗는 것도 모자라서 이젠 날 저놈들이랑 공범으로 몰아가려는 거지?","JPN":"ハッ！　そうよ！　私の役を奪った上に、私があいつらの共犯だって言い張るつもりなんでしょう！","ENG":"Ha! I get it! You’re trying to take my place, and you’re also trying to blame me for what happened?","TWN":"哈！你搶走我女主角的位置還不夠，現在還要汙衊我是那些傢伙的共犯嗎？"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"그만 둬.","JPN":"やめろ。","ENG":"Stop it.","TWN":"好了，"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"리허설은 끝났으니까.","JPN":"リハーサルは終わりだ。","ENG":"The rehearsal’s over.","TWN":"試鏡結束了，"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"자네가 뭐라하건 파벨라 역할에 가장 어울리는 건 유마 양이야.","JPN":"君が何と言おうが、ファヴェーラ役にもっとも相応しいのはユマさんだよ。","ENG":"No matter what you say, Miss Yuma is the one who fits the role of Fabella perfectly.","TWN":"不管你怎麼說，帕貝拉這個角色是非游馬小姐莫屬。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"자네에겐 파벨라보다 캐릭터에 좀 더 어울리는 조역을 맡기도록 하지.","JPN":"君にはファヴェーラより、もっとキャラクターに似合う助演を任せよう。","ENG":"I’ll give you a supporting role that fits your character.","TWN":"我會替你安排一個比帕貝拉更適合你的配角。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"하! 조역? 내가 그딴 엑스트라나 하려고 지금까지 노력한 거라 생각해요?","JPN":"ハッ！　助演？　私がエキストラなんかになるために今まで頑張ってきたと思ってるんですか？","ENG":"Hah! A supporting role?! Do you think I came all the way here just to play a supporting role?","TWN":"哈！配角？你以為我這麼努力，就只是為了演一個配角？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"연기라는 건 자신과 어울리는 역할을 맡았을 때 가장 빛나는 법입니다.","JPN":"演技とは、自分に相応しい役になった時もっとも光るのです。","ENG":"Acting skills shine the most when you play a role that suits you.","TWN":"作為一個演員，要得到適合自己的角色才能發光發熱。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"조명을 더 자주 받는다고 해서 더 나은 배우가 된다고 믿는 거라면…","JPN":"もっとスポットライトを浴びるからといって、よりいい俳優になるのだと信じているというのであれば……","ENG":"If you believe you become a better actress every time you get the spotlight...","TWN":"如果您認為要有更多的關注，才能成為更好的演員…"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그런 당신은 연기자가 아니라 단지 스타가 되고 싶었던 것 아닐까요?","JPN":"あなたは演技者ではなく、ただスターになりたかったのではないでしょうか？","ENG":"Then doesn’t that mean you just wanted to become a star and not an actress?","TWN":"那您應該是想成為明星，而不是演員，您說是嗎？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"그건…!","JPN":"それは……！","ENG":"That’s...!","TWN":"我…！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"당신… 당신이 날 속였어! 처음부터 이럴 작정이었지?","JPN":"あなた……あなたが私を騙したのよ！　最初からこうするつもりだったんでしょう！","ENG":"You... You tricked me! You were going to do this from the beginning, right?","TWN":"你…你騙我！你從一開始就是這麼盤算的吧？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"감독님! 난 지금 저 인간들한테 농락당하고 있는 거라고요!","JPN":"監督！　私は今、あいつらにたぶらかされてるんです！","ENG":"Mr. Director! Those people are trying to mess with me right now!","TWN":"導演！我是被這些人給設計的！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"저 인간들! 앞에선 날 도와주는 척하면서, 처음부터 배신할 작정이었던 거예요!","JPN":"あいつら、私を助けるふりをして、最初から裏切るつもりだったんですよ！","ENG":"Those people! Pretending to help me, they were planning to stab me in the back from the very beginning!","TWN":"他們表面上裝作要幫我，卻從一開始就打算要背叛我！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"맞아! 애초에 당신들은 저 유마란 여자를 배우로 만들어 주려고 판을 짰던 거야! 그렇지?","JPN":"そう！　そもそもあなたたちは、あのユマって女を女優にするために企んでたの！　そうなんでしょう！？","ENG":"Yes! You all planned this out to make Yuma an actress! Right?","TWN":"沒錯！你們本來就想把那個叫游馬的打造成演員，才故意設計我的吧？是不是！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 저희는 유마를 위해 아무것도 하지 않았답니다.","JPN":"フフ、私たちはユマのためには何もしていません。","ENG":"Ha ha, there’s nothing we did for Yuma.","TWN":"呵呵，我們並沒有替妹妹做什麼，"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"제 동생을 도와준 건 오히려 당신이었죠.","JPN":"私の妹に協力したのは、むしろあなたの方じゃありませんか。","ENG":"It was you who helped her out.","TWN":"反而是您在助妹妹一臂之力。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"그게 무슨 헛소리야?!","JPN":"ふざけないで！！","ENG":"What the hell is that supposed to mean?!","TWN":"你在胡說八道什麼？！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"유마는 당신이 자릴 비운 마지막 씬 촬영에서 대사를 까먹었답니다.","JPN":"ユマはあなたが席を外した最後のシーンでセリフを忘れていました。","ENG":"While you were away, Yuma forgot her lines when filming the final scene.","TWN":"你不在的時候，游馬在拍最後一個鏡頭時忘詞。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"…무, 뭐?","JPN":"……な、なんですって？","ENG":"...W-what?","TWN":"…什麼？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"쳇, 그런 긴 대본을 어떻게 다 외워? 나한테는 무리라고.","JPN":"チッ、あんな長いセリフを覚えられるわけないだろう？　アタシには無理だ。","ENG":"Sheesh, how can one even memorize a script that long? It was too much for me.","TWN":"嘖，那麼長的台詞是要怎麼背啦？我沒辦法！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"그게 진짜야?","JPN":"それって、本当？","ENG":"Is she for real?","TWN":"真的嗎？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"그런데 대체 어떻게 감독이 저런 좋은 평가를…?","JPN":"でも、いったいどうして監督はあんなにいい評価を……？","ENG":"Then why did the director compliment her acting...?","TWN":"那為什麼導演給出這麼高的評價…？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"하지만 다행히도, 느닷없는 동물들의 탈출과 무장괴한 분들의 등장 덕에 위기는 넘길 수 있었습니다.","JPN":"ですが幸い、いきなり動物たちが脱出し、武装集団が登場したおかげで危機を乗り切ることができました。","ENG":"But fortunately, thanks to the gunmen and sudden escape of the animals, Yuma went over the hump.","TWN":"幸好忘詞時候出現那些逃跑的動物和武裝分子，她才能度過危機。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"달려드는 짐승들을 눈빛 하나로 제압하고, 무대에 난입한 용병들로부터 파벨라가 로미오를 구해내는 멋진 장면을 담아내는데 성공했죠.","JPN":"襲い掛かってくる獣たちを視線だけで制圧し、舞台に乱入した傭兵たちからファヴェーラがロミオを助け出す素敵なシーンを撮影することに成功したのです。","ENG":"She overpowered the animals just with her eye gaze. The director eventually managed to capture a wonderful scene where Fabella saved Romeo from the mercenaries who stormed in.","TWN":"因此成功拍出帕貝拉一個眼神就震攝住那些狂奔而來的動物，又從那些亂入的傭兵手中救出羅密歐的精彩畫面。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"대사 한 마디 머뭇거린 일은 누구도 개의치 않을 만큼 좋은 장면이었습니다.","JPN":"セリフを1つ口ごもるくらい、誰も気にしないほどいいシーンでした。","ENG":"The scene was perfect enough to make no one mind about the line mistake.","TWN":"而且是精彩到沒人在意忘詞的事。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"그… 그럴 수가…….","JPN":"そ……そんな……","ENG":"That... can’t be...","TWN":"怎…怎麼會……"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"정정당당하게 각본에 쓰여진 대로 승부를 봤다면 결과는 달랐을 지도 모르지만…","JPN":"正々堂々、脚本に書かれたとおり勝負したら結果は違っていたのかもしれませんが……","ENG":"The results might have been different if you played the game fair and square, but...","TWN":"若是真的照劇本演出來決勝負，結果或許會不一樣…"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 이번엔 제 동생의 <color=#ffd34c>운</color>이 더 좋았군요.","JPN":"フフ、今回は私の妹のほうが<color=#ffd34c>運</color>がよかったですね。","ENG":"Ha ha, feels like my sister had better <color=#ffd34c>luck</color> this time.","TWN":"呵呵，但這次是我妹妹<color=#ffd34c>運氣</color>比較好。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"…용서 못해.","JPN":"……許さない。","ENG":"...You set me up...","TWN":"…不可原諒！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"그럼 당신은 이렇게 될 줄 다 알면서도…!","JPN":"じゃあ、あなたはこうなることを全部知っおきながら……！","ENG":"Then you knew what would happen...!","TWN":"你明知道會演變成這樣…！"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"나한테 그런 짓을 하라고 부추겼다는 거잖아! 그렇지?!","JPN":"私にあんなことをしろって煽ったわけね！　そうなんでしょう！？","ENG":"And you still made me do that kind of stuff! Right?!","TWN":"還慫恿我這麼做嗎？我說的對不對？！"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"난 당신을 믿었는데! 이런 식으로 배신을 해?!","JPN":"私はあなたを信じてたのに！　こんなふうに裏切るなんて！","ENG":"I trusted you, and you betray me like this?!","TWN":"我這麼相信你！你竟然背叛我？！"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"그만! 이러다 해 지겠어! 누가 좀 밖으로 끌어내!","JPN":"やめろ！　このままじゃ日が暮れるぞ！　誰か引っ張り出せ！","ENG":"Stop it! The sun’s going down! Someone take her out!","TWN":"好了！再吵下去太陽都要下山了！誰來把她帶走！"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"STAFF_NPC_DRAMA_NULL","text":{"KOREA":"저, 배우님. 촬영을 서둘러야 하니 우선 이쪽으로…","JPN":"あの、女優さん。急ぎで撮影を進めるので、早くこちらへ……","ENG":"Er, Miss actress. We have to rush, so please come here...","TWN":"小姐，我們還要趕著拍戲，請你先…"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"뭐야 넌? 직원 주제에 얻다 대고 명령질이야?","JPN":"何よ、あなた？　職員のくせに命令するんじゃないわよ！","ENG":"Who are you? You’re just a staff. How dare you give orders to me?","TWN":"你幹嘛你？一個小小的工作人員，現在是拿著雞毛當令箭嗎？"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L33_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"촬영은 집어치워!","JPN":"撮影なんてふざけないで！","ENG":"Forget the filming!","TWN":"不准拍！"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"날 이따위 취급하는 드라마를 내가 가만둘 것 같아?!","JPN":"私にこんなことするドラマに、私がただ黙ってると思う！？","ENG":"I won't let a TV series like this go smoothly!","TWN":"你們這樣對我，我還會讓你們拍下去嗎？！"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"캡틴 잭? 촬영장에 직원들을 괴롭히는 방해꾼이 있군요. 내쫓아주겠어요?","JPN":"キャプテン・ジャック？　撮影所に職員をいじめる邪魔者がいます。追い出してくれますか？","ENG":"Captain Jack? There’s a disturber that’s irritating the staff on set. Can you kick her out?","TWN":"傑克船長？拍攝現場有人在找工作人員的麻煩，可以請你把礙事的人趕走嗎？"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"STAFF_NPC_DRAMA_ROBOT","text":{"KOREA":"삐빅- 확인했습니다. 방해꾼을 촬영장으로부터 안전하게 배제합니다.","JPN":"ピピーッ。確認しました。邪魔者を撮影所から安全に排除します。","ENG":"Beep- Confirmed. Removing disturber from filming set.","TWN":"嗶嗶-收到。安全地將礙事的人從拍攝現場排除。"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_NPC_DRAMA_ROBOT","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"이 고철이 누가 방해꾼이라는 거야? 저리 안 꺼져?","JPN":"この鉄くずが、誰が邪魔者ですって！　どきなさい！","ENG":"You chunk of steel. Who do you think you’re calling a disturber? Get off!","TWN":"你這廢鐵說誰是礙事的人？給我滾開！"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"STAFF_NPC_DRAMA_ROBOT","text":{"KOREA":"그럼, 편안한 입수되십시오.","JPN":"では、楽しく泳いでください。","ENG":"Then, happy swimming.","TWN":"祝您戲水愉快。"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"이거 안 놔? 놓으라고!","JPN":"放しなさい！　放せって！","ENG":"Let go! Let go of me!","TWN":"還不放開？我叫你放開！"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_29"},{"id":"L44_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"꺄아아악!","JPN":"きゃあああっ！","ENG":"Aaaaagh!","TWN":"啊啊啊！"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};